// Normalize lookup output using ONLY current item fields and the lookup row if present.
// No references to $('Static pinned input') or any other node by name.
const incoming = $input.all();
const item = incoming[0] && incoming[0].json ? incoming[0].json : {};

// Pinned identity fields are flowed via $json (Data Table node passes them through current item)
const task_id = item.task_id;
const done_file_path = item.done_file_path;
const done_file_sha = item.done_file_sha;
const idempotency_key = item.idempotency_key;
const message_preview_safe = item.message_preview_safe;
const workflow_name = item.workflow_name;

// Data Table fields if a matching row exists
const existing_id = item.id ?? null;
const existing_notification_status = item.notification_status ?? null;
const existing_notified_at = item.notified_at ?? null;

const row_exists = existing_id !== null && existing_notification_status !== null;
const notification_state_decision = row_exists ? 'skip' : 'send';

return [{
  json: {
    task_id,
    done_file_path,
    done_file_sha,
    idempotency_key,
    message_preview_safe,
    workflow_name,
    row_exists,
    existing_id,
    existing_notification_status,
    existing_notified_at,
    notification_state_decision
  }
}];

// Build a safe Telegram payload using ONLY $json.* fields.
const item = $input.first().json;
const text = `[TEST pinned harness] task ${item.task_id} done\nidempotency_key:\n${item.idempotency_key}`;
return [{
  json: {
    text,
    task_id: item.task_id,
    done_file_path: item.done_file_path,
    done_file_sha: item.done_file_sha,
    idempotency_key: item.idempotency_key,
    message_preview_safe: item.message_preview_safe,
    workflow_name: item.workflow_name
  }
}];
